SELECT /*UserManageMapper.getMcpUserCntrInfoA*/ A.CONTRACT_NUM, A.SUBSCRIBER_NO AS MOBILE_NO, A.CUSTOMER_ID FROM MSP_JUO_SUB_INFO@DL_MSP A, MSP_JUO_CUS_INFO@DL_MSP B WHERE 1 = 1 AND A.CUSTOMER_ID = B.CUSTOMER_ID
AND A.SUBSCRIBER_NO = #{mobileNo}
AND A.CUSTOMER_ID = #{customerId}
AND A.SUB_STATUS = 'A'
